#include <bits/stdc++.h>
using namespace std;
int main(){long long n,m;scanf("%lld %lld",&n,&m);vector<long long>a(n);for(auto&x:a)scanf("%lld",&x);long long sum=0,best=LLONG_MAX;int l=0;for(int r=0;r<n;r++){sum+=a[r];while(sum>m){sum-=a[l++];}if(sum==m)best=min(best,(long long)(r-l+1));}printf("%lld\n",best==LLONG_MAX?0:best);}
